export default function PlantCard({ name, description, price, image }) {
  return (
    <div className="bg-white shadow-md rounded-lg overflow-hidden hover:scale-105 transition">
      <img src={image} alt={name} className="w-full h-48 object-cover" />
      <div className="p-4">
        <h3 className="text-lg font-semibold">{name}</h3>
        <p className="text-sm text-gray-600">{description}</p>
        <p className="text-green-700 font-bold mt-2">Rs. {price}/-</p>
        <button className="mt-3 bg-green-600 text-white px-4 py-2 rounded hover:bg-green-700">Buy</button>
      </div>
    </div>
  );
}
